{
  "analysis": "The strategy prioritizes discriminative power between live and dead scallops while providing sufficient distractor examples (Gunnels) to minimize false positives. We maintain the natural dominance of the live scallop class to reflect seafloor prevalence but upsample minority classes to a 1:2 or 1:3 ratio to ensure the loss function accounts for their features during fine-tuning.",
  "classes": [
    {
      "class_name": "Live Scallop",
      "current_count": 500,
      "target_count": 500,
      "strategy": "keep",
      "rationale": "As the primary target for detection and the most naturally abundant class, 500 annotations provide a solid baseline for fine-tuning without requiring immediate augmentation."
    },
    {
      "class_name": "Dead Scallop",
      "current_count": 50,
      "target_count": 250,
      "strategy": "upsample",
      "rationale": "Dead shells are the most common source of false positives for live scallops; increasing this count to a 1:2 ratio helps the model learn fine-grained discriminative features like mantle presence."
    },
    {
      "class_name": "Gunnel",
      "current_count": 30,
      "target_count": 150,
      "strategy": "upsample",
      "rationale": "Gunnels serve as a critical distractor class; upsampling ensures the model doesn't over-generalize 'any distinct object on sand' as a scallop, improving overall precision."
    }
  ]
}

